// Configurações fáceis de alterar.
const businessConfig = {
  // WhatsApp: troque o número abaixo pelo telefone real com DDI e DDD.
  whatsapp: "https://wa.me/5519974038120",
  phoneLabel: "(19) 97403-8120",

  // Instagram: troque se o perfil mudar.
  instagram: "https://www.instagram.com/cantinh0dosalgado/",

  // Cardápio: coloque aqui o link do cardápio completo quando tiver.
  menu: "#",

  // Endereço: altere o texto abaixo e coloque o link do Google Maps em location.
  address: "Rua Antonio Carlos Folegatti, Jd Nova Mercedes",
  location: "#",

  // Avaliação: coloque aqui o link de avaliação do Google ou formulário.
  review: "#",

  // Horário de funcionamento: altere livremente.
  hours: "Segunda a sábado, das 10h às 22h",

  // Imagens: troque por arquivos reais quando quiser.
  heroImage: "assets/hero-pastel.jpg",
  productImages: {
    pastel: "data:image/jpeg;base64,",
    coxinha: "data:image/jpeg;base64,",
    bolinha: "data:image/jpeg;base64,",
    bebidas: "data:image/jpeg;base64,"
  }
};

// Mensagem automática do WhatsApp.
const whatsappMessage = "Olá! Vim pelo Instagram e gostaria de fazer um pedido no Cantinho do Salgado.";

function buildWhatsappUrl() {
  return `${businessConfig.whatsapp}?text=${encodeURIComponent(whatsappMessage)}`;
}

function applyLinks() {
  const linkMap = {
    whatsapp: buildWhatsappUrl(),
    instagram: businessConfig.instagram,
    menu: businessConfig.menu,
    party: buildWhatsappUrl(),
    location: businessConfig.location,
    review: businessConfig.review
  };

  document.querySelectorAll("[data-link]").forEach((element) => {
    const key = element.dataset.link;
    const href = linkMap[key] || "#";

    element.setAttribute("href", href);

    if (href !== "#" && !href.startsWith("#")) {
      element.setAttribute("target", "_blank");
      element.setAttribute("rel", "noopener");
    }
  });
}

function applyBusinessInfo() {
  document.querySelectorAll("[data-business='phone']").forEach((element) => {
    element.textContent = businessConfig.phoneLabel;
  });

  document.querySelectorAll("[data-business='address']").forEach((element) => {
    element.textContent = businessConfig.address;
  });

  document.querySelectorAll("[data-business='hours']").forEach((element) => {
    element.textContent = businessConfig.hours;
  });
}

function applyImages() {
  const hero = document.querySelector("[data-hero-image]");

  if (hero && businessConfig.heroImage) {
    hero.style.backgroundImage = `linear-gradient(180deg, rgba(27, 18, 13, 0.18), rgba(27, 18, 13, 0.84)), url("${businessConfig.heroImage}")`;
  }

  document.querySelectorAll("[data-product-image]").forEach((element) => {
    const imageKey = element.dataset.productImage;
    const imagePath = businessConfig.productImages[imageKey];

    if (imagePath) {
      element.src = imagePath;
    }
  });
}

function initRevealOnScroll() {
  const revealItems = document.querySelectorAll(".reveal");

  if (!("IntersectionObserver" in window)) {
    revealItems.forEach((item) => item.classList.add("is-visible"));
    return;
  }

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        entry.target.classList.add("is-visible");
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.16 });

  revealItems.forEach((item) => observer.observe(item));
}

applyLinks();
applyBusinessInfo();
applyImages();
initRevealOnScroll();
